97	/**
98	 * Roadmap section — phase list with current phase highlighted and gate test checklist.
99	 * Gate evaluation for the current phase uses only results logged after phaseAdvancedAt
100	 * (if set). For Phase 1 (no advancement), all results are used.
101	 */
102	export function roadmapSection(
103	  phases: RoadmapPhase[],
104	  results: BenchmarkResultRow[],
105	  benchmarks: Benchmark[],
106	  currentPhaseId: string | null,
107	  phaseAdvancedAt?: string | null
108	): string {
109	  if (phases.length === 0) return "";
110	
111	  const resolved = resolvePhaseStatuses(phases, currentPhaseId);
112	  const currentPhaseResults = filterResultsSince(results, phaseAdvancedAt);
113	
114	  const items = resolved
115	    .map((phase) => {
116	      const isCurrent = phase.status === "current";
117	      const isCompleted = phase.status === "completed";
118	      const isFuture = phase.status === "future";
119	      const cls = isCurrent ? " roadmap-current" : isCompleted ? " completed" : "";
120	      const dotColor = isCurrent
121	        ? "var(--blue)"
122	        : isCompleted
123	          ? "var(--green)"
124	          : "var(--text-tertiary)";
125	
126	      let gateHtml = "";
127	      if (phase.gateTests && phase.gateTests.length > 0) {
128	        // Use filtered results for current phase, all results for completed phases
129	        const evalResults = isCurrent ? currentPhaseResults : results;
130	        const evaluation = isFuture ? null : evaluateGateTests(phase.gateTests, evalResults);
131	        const gateItems = phase.gateTests
132	          .map((gateId) => {
133	            const name = benchmarks.find((bm) => bm.id === gateId)?.name ?? gateId;
134	            if (isFuture) {
135	              return `<div class="gate-item">${escapeHtml(name)}</div>`;
136	            }
137	            const test = evaluation!.tests.find((t) => t.benchmarkId === gateId);
138	            const icon = test?.passed ? "\u2713" : "\u2717";
139	            const itemCls = test?.passed ? "gate-passed" : "gate-not-passed";
140	            return `<div class="gate-item ${itemCls}">${icon} ${escapeHtml(name)}</div>`;
141	          })
142	          .join("\n");
143	
144	        let allPassedBadge = "";
145	        if (evaluation?.allPassed && isCurrent) {
146	          allPassedBadge = `<div class="gate-all-passed">All gates passed \u2014 ready to advance</div>
147	<form data-on:submit__prevent="@post('/api/advance-phase/${escapeAttr(phase.id)}')" style="margin-top:8px">
148	  <button type="submit" class="btn btn-sm btn-primary">Advance to Next Phase</button>
149	</form>`;
150	        } else if (evaluation?.allPassed && isCompleted) {
151	          allPassedBadge = `<div class="gate-all-passed">All gates passed</div>`;
152	        }
153	
154	        gateHtml = `<div class="gate-checklist">
155	${gateItems}
156	${allPassedBadge}
157	</div>`;
158	      }
159	
160	      return `<div class="roadmap-item${cls}"><div class="roadmap-indicator" style="background:${dotColor}"></div><div><div class="roadmap-name">${escapeHtml(phase.name)}</div>
161	    ${phase.weeks ? `<div class="roadmap-weeks">${escapeHtml(phase.weeks)}</div>` : ""}
162	    ${phase.summary ? `<div class="roadmap-summary">${escapeHtml(phase.summary)}</div>` : ""}
163	    ${gateHtml}
164	  </div>
165	</div>`;
166	    })
