89	    const muscleGroups = new Set<string>();
90	    for (const ex of r.exercises) {
91	      const tmpl = templateMap.get(ex.exerciseTemplateId);
92	      if (tmpl) muscleGroups.add(tmpl.primaryMuscleGroup.replace(/_/g, " "));
93	    }
