134	export function foundationsSection(foundations: Foundation[]): string {
135	  if (foundations.length === 0) return "";
136	
137	  const cards = foundations.map((f, index) => {
138	    const signalName = `found_${f.id.replace(/[^a-zA-Z0-9]/g, "_")}`;
139	    const expanded = index === 0;
140	
141	    const stepsHtml = f.steps && f.steps.length > 0
142	      ? `<ol style="list-style:none;margin:0;padding:0">${f.steps.map((s) =>
143	          `<li style="padding:8px 0;border-top:1px solid var(--separator)">
144	  <div style="display:flex;gap:8px;align-items:baseline">
145	    ${s.step != null ? `<span style="font-size:13px;font-weight:700;color:var(--text-tertiary)">${s.step}</span>` : ""}
146	    <span style="font-size:14px;font-weight:600">${escapeHtml(s.name)}</span>
147	  </div>
148	  <div style="font-size:13px;color:var(--text-secondary);line-height:1.45;margin-top:4px;padding-left:${s.step != null ? "22px" : "0"}">${escapeHtml(s.instructions)}</div>
149	</li>`
150	        ).join("")}</ol>`
151	      : "";
152	
153	    const activeWeeks = f.activeDuringWeeks
154	      ? `<div style="font-size:12px;color:var(--text-tertiary);margin-top:8px">Active weeks ${f.activeDuringWeeks.start}\u2013${f.activeDuringWeeks.end}</div>`
155	      : "";
156	
157	    return `<div class="skill-card" data-signals:${signalName}="${expanded}">
158	  <div class="skill-header" data-on:click="$${signalName} = !$${signalName}">
159	    <span class="skill-name">${escapeHtml(f.title)}</span>
160	  </div>
161	  <div class="skill-body" data-show="$${signalName}">
162	    ${f.description ? `<div style="font-size:14px;color:var(--text-secondary);line-height:1.45;margin-bottom:12px">${escapeHtml(f.description)}</div>` : ""}
163	    ${stepsHtml}
164	    ${f.practice ? `<div style="font-size:13px;color:var(--green);margin-top:12px">${escapeHtml(f.practice)}</div>` : ""}
165	    ${activeWeeks}
166	  </div>
167	</div>`;
168	  });
169	
170	  return `<div class="section-header">Foundations</div>\n${cards.join("\n")}`;
171	}
172	
173	// ── Resources ──────────────────────────────────────────────────────
174	
175	export function resourcesSection(resources: Resource[]): string {
176	  if (resources.length === 0) return "";
177	
178	  const grouped = new Map<string, Resource[]>();
179	  for (const r of resources) {
180	    const cat = r.category ?? "General";
181	    const list = grouped.get(cat) ?? [];
182	    list.push(r);
183	    grouped.set(cat, list);
184	  }
185	
186	  const sections = Array.from(grouped.entries()).map(([category, items]) => {
187	    const itemsHtml = items.map((r) => {
188	      const inner = r.url
189	        ? `<a href="${escapeAttr(r.url)}" target="_blank" rel="noopener" style="font-size:15px;font-weight:600;color:var(--blue);text-decoration:none">${escapeHtml(r.title)}</a>`
190	        : `<div style="font-size:15px;font-weight:600">${escapeHtml(r.title)}</div>`;
191	      return `<div style="padding:10px 0;border-top:1px solid var(--separator)">
192	  ${inner}
193	  ${r.description ? `<div style="font-size:13px;color:var(--text-secondary);line-height:1.45;margin-top:2px">${escapeHtml(r.description)}</div>` : ""}
194	</div>`;
195	    }).join("");
196	
197	    return `<div style="font-size:13px;font-weight:600;color:var(--text-tertiary);margin-bottom:4px">${escapeHtml(category)}</div>${itemsHtml}`;
198	  }).join("");
199	
200	  return `<div class="section-header">Resources</div>
201	<div class="card">
202	${sections}
203	</div>`;
204	}
205	
206	// ── BODi Integration ───────────────────────────────────────────────
207	
208	export function bodiSection(items: BodiIntegration[]): string {
209	  if (items.length === 0) return "";
210	
211	  let html = "";
212	
213	  for (const b of items) {
214	    // Section header + description
215	    html += `<div class="section-header">BODi Integration</div>`;
216	    if (b.description) {
217	      html += `<div class="card"><div style="font-size:14px;color:var(--text-secondary);line-height:1.5">${escapeHtml(b.description)}</div></div>`;
218	    }
219	
220	    // Recommended programs
221	    if (b.recommendedPrograms && b.recommendedPrograms.length > 0) {
222	      html += bodiRecommendedProgramsHtml(b.recommendedPrograms);
223	    }
224	
225	    // Hybrid schedules
226	    if (b.hybridSchedules && b.hybridSchedules.length > 0) {
227	      html += bodiHybridSchedulesHtml(b.hybridSchedules);
228	    }
229	
230	    // Integration rules
231	    if (b.integrationRules && b.integrationRules.length > 0) {
232	      html += bodiIntegrationRulesHtml(b.integrationRules);
233	    }
234	
235	    // Legacy flat fields (backward compat)
236	    if (!b.recommendedPrograms && !b.hybridSchedules && !b.integrationRules) {
237	      html += `<div class="card">
238	  <div style="font-size:15px;font-weight:600">${escapeHtml(b.title)}</div>
239	  ${b.schedule ? `<div style="font-size:13px;color:var(--blue);margin-top:4px">${escapeHtml(b.schedule)}</div>` : ""}
240	  ${b.notes ? `<div style="font-size:13px;color:var(--text-tertiary);margin-top:4px">${escapeHtml(b.notes)}</div>` : ""}
241	</div>`;
242	    }
243	  }
244	
245	  return html;
246	}
247	
248	function bodiRecommendedProgramsHtml(programs: BodiRecommendedProgram[]): string {
249	  const cards = programs.map((p) => {
250	    const labelColor = p.fitLabelColor ?? "var(--blue)";
251	    const badge = p.fitLabel
252	      ? `<span style="display:inline-block;font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:${escapeAttr(labelColor)};background:${escapeAttr(labelColor)}1a;padding:2px 8px;border-radius:4px">${escapeHtml(p.fitLabel)}</span>`
253	      : "";
254	
255	    const meta: string[] = [];
256	    if (p.trainer) meta.push(escapeHtml(p.trainer));
257	    if (p.duration) meta.push(escapeHtml(p.duration));
258	    const metaLine = meta.length > 0
259	      ? `<div style="font-size:12px;color:var(--text-tertiary);margin-top:2px">${meta.join(" \u00B7 ")}</div>`
260	      : "";
261	
262	    return `<div style="padding:12px 0;border-top:1px solid var(--separator)">
263	  <div style="display:flex;align-items:center;gap:8px">
264	    <div style="font-size:15px;font-weight:600">${escapeHtml(p.name)}</div>
265	    ${badge}
266	  </div>
267	  ${metaLine}
268	  ${p.description ? `<div style="font-size:13px;color:var(--text-secondary);line-height:1.45;margin-top:6px">${escapeHtml(p.description)}</div>` : ""}
269	  ${p.whenToUse ? `<div style="font-size:13px;color:var(--green);line-height:1.45;margin-top:6px">${escapeHtml(p.whenToUse)}</div>` : ""}
270	  ${p.cautions ? `<div style="font-size:13px;color:var(--orange);line-height:1.45;margin-top:4px">${escapeHtml(p.cautions)}</div>` : ""}
271	</div>`;
272	  }).join("");
273	
274	  return `<div class="section-header" style="font-size:13px">Recommended Programs</div>
275	<div class="card">
276	${cards}
277	</div>`;
278	}
279	
280	function bodiHybridSchedulesHtml(schedules: BodiHybridSchedule[]): string {
281	  const sections = schedules.map((sched, index) => {
282	    const signalName = `bodi_sched_${index}`;
283	
284	    const rows = sched.days.map((d) => {
285	      const cells: string[] = [];
286	      cells.push(`<div style="font-size:13px;font-weight:600;min-width:80px">${escapeHtml(d.day)}</div>`);
287	
288	      const sessions: string[] = [];
289	      if (d.mobilitySession) sessions.push(`<span style="color:var(--green)">${escapeHtml(d.mobilitySession)}</span>`);
290	      if (d.bodiSession) sessions.push(`<span style="color:var(--blue)">${escapeHtml(d.bodiSession)}</span>`);
291	      if (sessions.length === 0 && d.notes) sessions.push(`<span style="color:var(--text-tertiary)">${escapeHtml(d.notes)}</span>`);
292	
293	      cells.push(`<div style="font-size:13px;flex:1">${sessions.join(`<span style="color:var(--text-tertiary)"> + </span>`)}</div>`);
294	
295	      if (sessions.length > 0 && d.notes) {
296	        cells.push(`<div style="font-size:12px;color:var(--text-tertiary);max-width:200px;text-align:right">${escapeHtml(d.notes)}</div>`);
297	      }
298	
299	      return `<div style="display:flex;align-items:baseline;gap:12px;padding:8px 0;border-top:1px solid var(--separator)">${cells.join("")}</div>`;
300	    }).join("");
301	
302	    return `<div class="skill-card" data-signals:${signalName}="${index === 0}">
303	  <div class="skill-header" data-on:click="$${signalName} = !$${signalName}">
304	    <span class="skill-name">${escapeHtml(sched.name)}</span>
305	  </div>
306	  <div class="skill-body" data-show="$${signalName}">
307	    ${sched.description ? `<div style="font-size:13px;color:var(--text-secondary);line-height:1.45;margin-bottom:8px">${escapeHtml(sched.description)}</div>` : ""}
308	    ${rows}
309	  </div>
310	</div>`;
311	  }).join("\n");
312	
313	  return `<div class="section-header" style="font-size:13px">Hybrid Schedules</div>\n${sections}`;
314	}
315	
316	function bodiIntegrationRulesHtml(rules: BodiIntegrationRule[]): string {
317	  const sorted = [...rules].sort((a, b) => (a.priority ?? 99) - (b.priority ?? 99));
318	
319	  const categoryColors: Record<string, string> = {
320	    ordering: "var(--blue)",
321	    safety: "var(--orange)",
322	    timing: "var(--green)",
323	  };
324	
325	  const items = sorted.map((r) => {
326	    const catColor = r.category ? (categoryColors[r.category] ?? "var(--text-tertiary)") : "var(--text-tertiary)";
327	    const catBadge = r.category
328	      ? `<span style="display:inline-block;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:${catColor};margin-right:6px">${escapeHtml(r.category)}</span>`
329	      : "";
330	
331	    return `<div style="padding:8px 0;border-top:1px solid var(--separator);display:flex;align-items:baseline;gap:8px">
332	  <div style="font-size:13px;font-weight:700;color:var(--text-tertiary);min-width:18px">${r.priority ?? ""}</div>
333	  <div style="flex:1">
334	    ${catBadge}<span style="font-size:13px;line-height:1.45">${escapeHtml(r.rule)}</span>
335	  </div>
336	</div>`;
337	  }).join("");
338	
339	  return `<div class="section-header" style="font-size:13px">Integration Rules</div>
340	<div class="card">
341	${items}
342	</div>`;
343	}
344	
345	// ── Program Library section ──────────────────────────────────────────
346	
347	/**
348	 * Lists all programs in the user's library with switch/delete actions.
349	 * Only shown when more than one program exists.
350	 */
351	export function programLibrarySection(programs: ProgramRow[]): string {
352	  const items = programs.map((p) => {
353	    const parsed = (() => {
354	      try {
355	        return JSON.parse(p.json_data) as { meta?: { title?: string; subtitle?: string } };
356	      } catch {
357	        return null;
358	      }
359	    })();
360	    const title = parsed?.meta?.title ?? `Program #${p.id}`;
361	    const subtitle = parsed?.meta?.subtitle;
362	    const isActive = p.is_active === 1;
363	    const uploadedDate = p.created_at.slice(0, 10);
364	
365	    const activeBadge = isActive
366	      ? `<span style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--green);background:rgba(48,209,88,0.12);padding:2px 8px;border-radius:4px;margin-left:8px">Active</span>`
367	      : "";
368	
369	    const actions = isActive
370	      ? ""
371	      : `<div style="display:flex;gap:8px;margin-top:8px">
372	  <button class="btn btn-blue" style="font-size:12px;padding:4px 14px;height:auto"
373	    data-on:click="@post('/api/switch-program/${p.id}')">Switch To</button>
374	  <button class="btn" style="font-size:12px;padding:4px 14px;height:auto;color:var(--orange);border-color:var(--orange)"
375	    data-on:click="@post('/api/delete-program/${p.id}')">Delete</button>
376	</div>`;
377	
378	    return `<div style="padding:12px 0;${isActive ? "" : "opacity:0.75"}">
379	  <div style="display:flex;align-items:center">
380	    <span style="font-size:15px;font-weight:600">${escapeHtml(title)}</span>
381	    ${activeBadge}
382	  </div>
383	  ${subtitle ? `<div style="font-size:13px;color:var(--text-secondary);margin-top:2px">${escapeHtml(subtitle)}</div>` : ""}
384	  <div style="font-size:12px;color:var(--text-tertiary);margin-top:2px">Imported ${escapeHtml(uploadedDate)}</div>
385	  ${actions}
386	</div>`;
387	  }).join(`<div style="border-top:1px solid var(--separator)"></div>`);
388	
389	  return `<div class="section-header">Program Library</div>
390	<div class="card">
391	${items}
392	</div>`;
393	}
394	
395	// ── Import Program section ──────────────────────────────────────────
396	
397	/**
398	 * Collapsible "Import New Program" section shown at the bottom of the
399	 * Program page. Mirrors the setup page upload/validate flow but posts
400	 * to /api/validate-import-program and /api/import-program.
401	 *
402	 * Signals used (all scoped to this element via data-signals):
403	 *   $importOpen        — whether the section is expanded
404	 *   $importProgramJson — the uploaded JSON string (Datastar converts kebab to camelCase)
405	 *   $importTemplateId  — the selected week template ID
406	 */
407	export function importProgramSection(): string {
408	  return `<div data-signals:import-open="false" data-signals:import-program-json="''" data-signals:import-template-id="''">
409	  <div class="section-header" style="display:flex;align-items:center;justify-content:space-between">
410	    <span>Import Program</span>
411	    <button
412	      class="btn btn-blue"
413	      style="font-size:12px;padding:4px 12px;height:auto"
414	      data-on:click="$importOpen = !$importOpen"
415	    >
416	      <span data-text="$importOpen ? 'Cancel' : 'Upload JSON'">Upload JSON</span>
417	    </button>
418	  </div>
419	
420	  <div data-show="$importOpen">
421	    <div class="card" style="margin-bottom:12px">
422	      <div class="form-group" style="margin-bottom:16px">
423	        <label class="form-label">Program JSON File</label>
424	        <input type="file" accept=".json" class="form-input"
425	          data-on:change="
426	            const f = evt.target.files[0];
427	            if (!f) return;
428	            f.text().then(t => {
429	              const el = document.getElementById('importProgramData');
430	              el.value = t;
431	              el.dispatchEvent(new Event('input', {bubbles: true}));
432	              $importTemplateId = '';
433	              document.getElementById('import-validation-result').innerHTML = '';
434	            });
435	          " />
436	        <input type="text" id="importProgramData" data-bind:import-program-json style="display:none" />
437	      </div>
438	      <button
439	        class="btn btn-blue btn-block"
440	        data-on:click="@post('/api/validate-import-program')"
441	      >
442	        Validate &amp; Preview
443	      </button>
444	    </div>
445	
446	    <div id="import-validation-result"></div>
447	
448	    <div data-show="$importTemplateId !== ''" style="margin-top:12px">
449	      <button
450	        class="btn btn-blue btn-block"
451	        data-on:click="@post('/api/import-program')"
452	      >
453	        Apply Program
454	      </button>
455	    </div>
456	  </div>
457	</div>`;
458	}
459	
460	/**
461	 * SSE fragment: week template selection cards for the import flow.
462	 * Rendered inside #import-validation-result after successful validation.
463	 * Clicking a card sets $importTemplateId and shows the Apply button.
464	 */
465	export function importTemplateSelectionFragment(templates: WeekTemplate[]): string {
466	  const grid = renderTemplateGrid(
467	    templates,
468	    (id) =>
469	      `data-on:click="$importTemplateId = '${escapeAttr(id)}'" data-class:selected="$importTemplateId === '${escapeAttr(id)}'"`,
470	  );
471	
472	  return `<div class="card" style="margin-bottom:0">
473	  <div class="form-group" style="margin-bottom:0">
474	    <label class="form-label">Choose Schedule</label>
475	    ${grid}
476	  </div>
477	</div>`;
478	}
