}

.tab-icon {
  width: 24px;
  height: 24px;
}

.tab-label {
  font-size: 10px;
}

/* ── Separators ── */
.separator {
  height: 1px;
  background: var(--separator);
  margin: 12px 0;
}

/* ── Completed items ── */
.completed-item {
  display: flex;
