    currentPhaseId,
    gateEvaluation
  );

  if (!validation.ok) {
    if (validation.error === "not_found") {
      return new Response("Phase not found", { status: 404 });
    }
    if (validation.error === "already_completed") {
      return new Response("Phase already completed", { status: 400 });
    }
    if (validation.error === "not_current") {
      return new Response("Phase is not current", { status: 400 });
    }
    // gates_not_passed
    const message = `Gates not passed: ${(validation.failingGates ?? []).join(", ")}`;
    return new Response(message, { status: 400 });
  }

  if ("lastPhase" in validation && validation.lastPhase) {
    // Last phase completed — mark it as done by advancing past it
    // Store the completed phase ID so resolvePhaseStatuses marks all as completed
    await advancePhase(env.DB, userId, programId, `${phaseId}:completed`);
    return new Response(null, { status: 202 });
  }

  await advancePhase(env.DB, userId, programId, validation.nextPhaseId);

  return new Response(null, { status: 202 });
}

